document.addEventListener("DOMContentLoaded", () => {
  "use strict";

  // 1. 独家性能优化：Intersection Observer 视频懒加载
  const lazyVideos = document.querySelectorAll('video.lazy-video');
  if ('IntersectionObserver' in window) {
    const videoObserver = new IntersectionObserver((entries, observer) => {
      entries.forEach(entry => {
        if (entry.isIntersecting) {
          const video = entry.target;
          video.src = video.dataset.src; 
          video.load();
          video.play().catch(e => console.log("Auto-play blocked:", e));
          video.classList.remove('lazy-video');
          observer.unobserve(video); 
        }
      });
    }, { rootMargin: "0px 0px 200px 0px" });
    
    lazyVideos.forEach(video => {
      videoObserver.observe(video);
    });
  } else {
    // 兼容旧版浏览器
    lazyVideos.forEach(video => {
      video.src = video.dataset.src;
      video.load();
    });
  }

  // 2. 表单联动功能 (原封不动保留)
  const colorData = {
    A:[['A1','1. White'],['A2','2. Beige'],['A3','3. Gray'],['A4','4. Dark Gray'],['A5','5. Brown'],['A6','6. Black']],
    B:[['B1','1. White'],['B2','2. Dark Gray'],['B3','3. Beige'],['B4','4. Dark Gray']],
    C:[['C1','1. Beige'],['C2','2. Brown'],['C3','3. Light Gray'],['C4','4. Dark Gray'],['C5','5. Black']],
    D:[['D1','1. White'],['D2','2. Yellow'],['D3','3. Dark Brown'],['D4','4. Light Gray'],['D5','5. Dark Gray'],['D6','6. Black Gray'],['D7','7. Black']],
    E:[['E1','1. White'],['E2','2. Beige'],['E3','3. Brown'],['E4','4. Light Gray'],['E5','5. Black']],
    F:[['F1','1. Light Gray'],['F2','2. Brown'],['F3','3. Black']]
  };
  
  const openness = document.getElementById('opennessType');
  const fabColor = document.getElementById('fabricColorChoice');
  const aluColor = document.getElementById('aluminiumColorChoice');
  
  if (openness && fabColor && aluColor) {
    openness.addEventListener('change', e => {
      const v = e.target.value;
      aluColor.style.display='';
      aluColor.required=true;
      fabColor.innerHTML = '<option value="" disabled selected>Select Fabric Color (A–F)</option>';
      if(colorData[v]){
        colorData[v].forEach(([val,label])=>{
          const opt=document.createElement('option');
          opt.value=val; opt.textContent=label;
          fabColor.appendChild(opt);
        });
      }
    });
  }

  // 3. WhatsApp 报价发送功能 (防连点保护)
  const form = document.getElementById('budgetForm');
  let isSubmitting = false;

  if (form) {
    form.addEventListener('submit', (e) => {
      e.preventDefault();
      
      if (isSubmitting) return;

      const n = document.getElementById('qName').value.trim();
      const a = document.getElementById('qAddress').value.trim();
      const h = document.getElementById('qHeight').value;
      const l = document.getElementById('qLength').value;
      const o = openness.value;
      const fc = fabColor.value;
      const ac = aluColor.value;

      if(!n || !a) {
          alert("Please fill in your Name and Address.");
          return;
      }
      
      isSubmitting = true;
      setTimeout(() => { isSubmitting = false; }, 3000); // 3秒防抖

      const text = `Hi Lion Sin, I'd like a quote!%0A%0AName: ${encodeURIComponent(n)}%0AAddress: ${encodeURIComponent(a)}%0ABalcony Height: ${encodeURIComponent(h)}m%0ABalcony Length: ${encodeURIComponent(l)}m%0AOpenness: ${encodeURIComponent(o)}%0AFabric Color: ${encodeURIComponent(fc)}%0AAluminium Color: ${encodeURIComponent(ac)}`;
      
      window.open(`https://wa.me/6583417888?text=${text}`,'_blank');
    });
  }

  // 4. 图片点击放大 (Lightbox) 功能
  const lightbox = document.getElementById("imageLightbox");
  const lightboxImg = document.getElementById("lightboxImg");
  const captionText = document.getElementById("lightboxCaption");
  const closeBtn = document.getElementsByClassName("close-lightbox")[0];
  const zoomableImages = document.querySelectorAll('.zoomable');

  if (lightbox && zoomableImages.length > 0) {
    zoomableImages.forEach(img => {
      img.addEventListener('click', function() {
        lightbox.style.display = "block";
        lightboxImg.src = this.src;
        // 抓取图片旁边的 h4 作为弹窗的金色标题文字
        const textNode = this.nextElementSibling ? this.nextElementSibling.querySelector('h4') : null;
        captionText.innerHTML = textNode ? textNode.innerText : this.alt;
      });
    });

    // 点击 X 按钮关闭
    closeBtn.onclick = function() {
      lightbox.style.display = "none";
    }

    // 点击背景黑框也能关闭
    lightbox.onclick = function(e) {
      if(e.target === lightbox) {
        lightbox.style.display = "none";
      }
    }
    
    // 按键盘 ESC 键关闭
    document.addEventListener('keydown', function(e) {
      if (e.key === "Escape" && lightbox.style.display === "block") {
        lightbox.style.display = "none";
      }
    });
  }
});
